<script lang="ts">
import { defineComponent, ref, onMounted, computed } from 'vue';
import Button from 'primevue/button'
import { TickerTape, ForexCrossRates } from '../components/Widgets'
import { PricingCard, Testimonials } from '../components'
import type { InvestmentPlan } from '../types/investments'
import { formatCurrency } from "@/lib";
import { accountService } from '@/lib/accountService'
import { investmentService } from '@/lib/investmentService'

interface Slide {
    title: string
    subtitle: string
    text: string
    image: string
    route?: string
}

export default defineComponent({
    setup() {
        const appName = import.meta.env.VITE_APP_NAME
        // const proc = import.meta.env.APP
        const service = investmentService()

        const plans = computed(() => {
            return service.active_plans.value
        })

        const sliders = ref<Slide[]>([
            {
                title: "They Are Fast",
                subtitle: "We Are Faster",
                text: "Trade crude, Gold, CFD on shares, Crypto and indices with lightning speed on the world's biggest markets; like a pro.",
                image: 'img/fast.png',
                route: "Register"
            },
            {
                title: "Trade The World's Biggest Markets",
                subtitle: "Earn Passive Revenue",
                text: "Trade crude, Gold, CFD on shares, Crypto and indices with lightning speed on the world's biggest markets; like a pro.",
                image: 'img/farm.jpeg',
                route: "Register"
            }
        ])
        const sliderOptions = ref([
            {
                breakpoint: '1400px',
                numVisible: 1,
                numScroll: 1
            },
            {
                breakpoint: '1199px',
                numVisible: 1,
                numScroll: 1
            },
            {
                breakpoint: '767px',
                numVisible: 1,
                numScroll: 1
            },
            {
                breakpoint: '575px',
                numVisible: 1,
                numScroll: 1
            }
        ]);
        

        onMounted(() => {
            // destroyLoader()
            // isLoading = true
            // displayLoader()
            service.getPlans()
            // account.getWalletBalance().then((wallet_balance: number) => {
            //     balance.value = wallet_balance
            // })
        })
        return { appName, plans, sliders, sliderOptions }
    },
    components: {
        Button,
        TickerTape,
        ForexCrossRates,
        PricingCard,
        Testimonials
    }
})
</script>